import React from "react";

function CssCanvas(props){
    const canvasStyle = {
        display: props.displayType, gridTemplateColumns: props.rowsColumns.gridColumn, gridTemplateRows: props.rowsColumns.gridRow
    }

    // const displayType = props.displayType;
    // const gridRows = props.rowsColumns.gridRow;
    // const gridColumns = props.rowsColumns.gridColumn;

    return (
        <div className="CssCanvas" style={canvasStyle}>
            <div className="boxes">1</div>
            <div className="boxes">2</div>
            <div className="boxes">3</div>
            <div className="boxes">4</div>
            <div className="boxes">5</div>
        </div>
    );
}

export default CssCanvas;
